## components/DroneFleet.tsx

Updated to remove specific outer container styling where it conflicted with `WindowFrame`, keeping the

The "Maximize" functionality will be enhanced to detach the window from the grid layout, allowing it to float above the interface. In this floating state, the window will be draggable via its header, enabling users to position it anywhere within the browser viewport (and across monitors if the browser window spans them). The "Minimize" (Yellow) button will serve as a "Restore" function when floating, returning the window to its original docked position in the grid.

Here are the updated files.

# Updated files:

## components/WindowFrame.tsx

-   Replaced the simple `maximized` state with `isFloating` state.
-   Implemented drag-and-drop logic using `mousedown`, `mousemove`, and `mouseup` event listeners on the header.
-   Added logic to capture the element's dimensions and position before floating to ensure a smooth transition.
-   Updated the "Minimize" (yellow) button to act as a "Restore" button when the window is floating, returning it to the grid. When docked, it continues to toggle content visibility.
-   Updated the "Maximize" (green) button to toggle the floating state.

```tsx
import React, { useState, useRef, useEffect } from 'react';

interface WindowFrameProps {
    title: React.ReactNode;
    children: React.ReactNode;
    className?: string;
    onClose?: () => void;
    headerRight?: React.ReactNode;
}

export const WindowFrame: React.FC<WindowFrameProps> = ({ title, children, className = "", onClose, headerRight }) => {
    const [contentMinimized, setContentMinimized] = useState(false);
    const [isFloating, setIsFloating] = useState(false);
    const [closed, setClosed] = useState(false);
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [size, setSize] = useState<{ width: string | number, height: string | number }>({ width: 'auto', height: 'auto' });

    const frameRef = useRef<HTMLDivElement>(null);
    const dragRef = useRef<{ startX: number, startY: number, initialX: number, initialY: number } | null>(null);

    // Toggle between Floating (Maximized/Movable) and Docked (Grid) modes
    const toggleFloat = () => {
        if (!isFloating) {
            // Entering float mode: Capture current rect to prevent jumping
            if (frameRef.current) {
                const rect = frameRef.current.getBoundingClientRect();
                setPosition({ x: rect.left, y: rect.top });
                // Ensure it has explicit dimensions when floating
                setSize({ width: rect.width, height: rect.height });
            }
            setIsFloating(true);
            setContentMinimized(false); // Always show content when popping out
        } else {
            // Exiting float mode: Return to grid
            setIsFloating(false);
            setSize({ width: 'auto', height: 'auto' });
        }
    };

    // Logic for the Yellow "Minimize" button
    const handleMinimizeClick = () => {
        if (isFloating) {
            // If floating, return to original position (Restore)
            toggleFloat();
        } else {
            // If docked, toggle content visibility (Collapse)
            setContentMinimized(!contentMinimized);
        }
    };

    const handleMouseDown = (e: React.MouseEvent) => {
        // Only allow dragging when floating
        if (!isFloating) return;

        // Prevent dragging if clicking buttons in the header
        if ((e.target as HTMLElement).closest('button')) return;

        dragRef.current = {
            startX: e.clientX,
            startY: e.clientY,
            initialX: position.x,
            initialY: position.y
        };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
        e.preventDefault(); // Prevent text selection during drag
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (!dragRef.current) return;
        const dx = e.clientX - dragRef.current.startX;
        const dy = e.clientY - dragRef.current.startY;
        setPosition({
            x: dragRef.current.initialX + dx,
            y: dragRef.current.initialY + dy
        });
    };

    const handleMouseUp = () => {
        dragRef.current = null;
        document.removeEventListener('mousemove', handleMouseMove);
        document.removeEventListener('mouseup', handleMouseUp);
    };

    // Cleanup event listeners on unmount
    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };
    }, []);

    if (closed) return null;

    // Floating styles: Fixed position, high z-index, shadow
    const floatClasses = "fixed z-50 shadow-2xl border-gray-600";
    // Docked styles: Relative position, uses passed className for grid layout
    const dockClasses = `relative ${className}`;

    const combinedClasses = `bg-gray-800 rounded-lg flex flex-col transition-shadow duration-200 border border-gray-700 ${isFloating ? floatClasses : dockClasses}`;

    // Apply inline styles for position and size only when floating
    const style: React.CSSProperties = isFloating ? {
        left: position.x,
        top: position.y,
        width: size.width,
        height: size.height,
        margin: 0,
    } : {};

    return (
        <div 
            ref={frameRef}
            className={combinedClasses}
            style={style}
        >
            {/* Header Bar */}
            <div 
                className={`flex items-center justify-between px-4 py-2 border-b border-gray-700 bg-gradient-to-r from-gray-800 to-gray-750 rounded-t-lg select-none ${isFloating ? 'cursor-move' : ''}`}
                onMouseDown={handleMouseDown}
                onDoubleClick={toggleFloat}
            >
                <div className="flex items-center gap-3 overflow-hidden">
