import React, { useState, useRef, useEffect } from 'react';

interface WindowFrameProps {
    title: React.ReactNode;
    children: React.ReactNode;
    className?: string;
    onClose?: () => void;
    headerRight?: React.ReactNode;
}

export const WindowFrame: React.FC<WindowFrameProps> = ({ title, children, className = "", onClose, headerRight }) => {
    const [contentMinimized, setContentMinimized] = useState(false);
    const [isFloating, setIsFloating] = useState(false);
    const [closed, setClosed] = useState(false);
    const [isDragging, setIsDragging] = useState(false);

    // State for floating behavior
    const [position, setPosition] = useState({ x: 0, y: 0 });
    const [dimensions, setDimensions] = useState<{ width: number | string, height: number | string }>({ width: 'auto', height: 'auto' });

    const frameRef = useRef<HTMLDivElement>(null);
    const dragRef = useRef<{ startX: number, startY: number, initialX: number, initialY: number } | null>(null);

    // Handlers
    const onDrag = (e: MouseEvent) => {
        if (!dragRef.current) return;
        const deltaX = e.clientX - dragRef.current.startX;
        const deltaY = e.clientY - dragRef.current.startY;

        setPosition({
            x: dragRef.current.initialX + deltaX,
            y: dragRef.current.initialY + deltaY
        });
    };

    const stopDrag = () => {
        setIsDragging(false);
        dragRef.current = null;
        document.removeEventListener('mousemove', onDrag);
        document.removeEventListener('mouseup', stopDrag);
    };

    const startDrag = (e: React.MouseEvent) => {
        if (!isFloating) return;
        // Prevent dragging if clicking buttons in the header
        if ((e.target as HTMLElement).closest('button')) return;

        // Prevent text selection, but allow events to propagate to handle double-click
        e.preventDefault();

        setIsDragging(true);

        dragRef.current = {
            startX: e.clientX,
            startY: e.clientY,
            initialX: position.x,
            initialY: position.y
        };

        document.addEventListener('mousemove', onDrag);
        document.addEventListener('mouseup', stopDrag);
    };

    const toggleFloat = () => {
        if (!isFloating) {
            // Docked -> Floating
            if (frameRef.current) {
                const rect = frameRef.current.getBoundingClientRect();
                setPosition({ x: rect.left, y: rect.top });
                setDimensions({ width: rect.width, height: rect.height });
            }
            setIsFloating(true);
            setContentMinimized(false); // Always show content when floating
        } else {
            // Floating -> Docked
            setIsFloating(false);
            setDimensions({ width: 'auto', height: 'auto' });
        }
    };

    const handleMinimize = () => {
        if (isFloating) {
            // If floating, Restore to dock
            toggleFloat();
        } else {
            // If docked, toggle content collapse
            setContentMinimized(!contentMinimized);
        }
    };

    // Ensure useEffect is called unconditionally
    useEffect(() => {
        return () => {
            document.removeEventListener('mousemove', onDrag);
            document.removeEventListener('mouseup', stopDrag);
        };
    }, []);

    // Early return MUST happen after all hooks
    if (closed) return null;

    // Dynamic Transition: Disable transition during drag for 1:1 responsiveness
    const transitionStyle = isDragging ? 'transition-none' : 'transition-all duration-300 ease-[cubic-bezier(0.25,1,0.5,1)]';

    // Frame styles
    const frameClasses = `bg-gray-800 rounded-lg flex flex-col overflow-hidden ${transitionStyle} ${
        isFloating 
            ? `fixed z-50 backdrop-blur-sm ${
                isDragging 
                    ? 'shadow-[0_35px_60px_-15px_rgba(0,0,0,0.8)] border-cyan-400 ring-1 ring-cyan-400 scale-[1.005]' // Active Drag: Lifted higher, highlighted
                    : 'shadow-[0_25px_50px_-12px_rgba(0,0,0,0.7)] border-cyan-500/40 ring-1 ring-cyan-500/20' // Idle Float
              }`
            : 'relative h-full border border-gray-700 hover:border-gray-600 hover:shadow-xl hover:-translate-y-0.5' // Docked
    }`;

    const frameStyle: React.CSSProperties = isFloating ? {
        left: position.x,
        top: position.y,
        width: dimensions.width,
        height: dimensions.height,
        margin: 0,
    } : {};

    // Determine cursor style based on state
    const headerCursorClass = isFloating 
        ? (isDragging ? 'cursor-grabbing' : 'cursor-move') 
        : 'cursor-pointer'; // Pointer indicates clickable (double-click to maximize)

    const renderFrame = () => (
        <div 
            ref={frameRef}
            className={`${frameClasses} ${!isFloating ? className : ''}`}
            style={frameStyle}
        >
            <div 
                className={`flex items-center justify-between px-4 py-2 border-b border-gray-700 bg-gradient-to-r from-gray-800 to-gray-750 rounded-t-lg select-none ${headerCursorClass}`}
                onMouseDown={startDrag}
                onDoubleClick={toggleFloat}
            >
                <div className="flex items-center gap-3 overflow-hidden">
                    <div className="flex items-center gap-1.5 mr-2">
                         <button 
                            onClick={(e) => { e.stopPropagation(); if (onClose) onClose(); else setClosed(true); }} 
                            className="w-3 h-3 rounded-full bg-red-500 hover:bg-red-600 transition-colors focus:outline-none" 
                            title="Close"
                            aria-label="Close"
                        />
                        <button 
                            onClick={(e) => { e.stopPropagation(); handleMinimize(); }} 
                            className="w-3 h-3 rounded-full bg-yellow-500 hover:bg-yellow-600 transition-colors focus:outline-none" 
                            title={isFloating ? "Restore to Dock" : (contentMinimized ? "Expand" : "Collapse")}
                            aria-label={isFloating ? "Restore" : "Minimize"}
                        />
                        <button 
                            onClick={(e) => { e.stopPropagation(); toggleFloat(); }} 
                            className="w-3 h-3 rounded-full bg-green-500 hover:bg-green-600 transition-colors focus:outline-none" 
                            title={isFloating ? "Dock" : "Float"}
                            aria-label={isFloating ? "Dock" : "Maximize"}
                        />
                    </div>
                    <div className="text-sm font-bold uppercase tracking-wide text-gray-200 truncate flex items-center gap-2">
                        {title}
                    </div>
                </div>
                <div className="flex items-center pl-2">
                    {headerRight}
                </div>
            </div>

            {!contentMinimized && (
                <div className="flex-grow overflow-auto flex flex-col">
                    {children}
                </div>
            )}
        </div>
    );

    if (isFloating) {
        return (
            <>
                {/* Placeholder to maintain grid layout prevents collapse when window floats */}
                <div className={`${className}`} style={{ height: dimensions.height, width: '100%', visibility: 'hidden' }} />
                {renderFrame()}
            </>
        );
    }

    return renderFrame();
}

