                                        description: "The full text of the draft reply."
                                    }
                                }
                            }
                        }
                    }
                }
            }
        });

        const jsonText = response.text.trim();
        const parsedResponse: AICommResponse = JSON.parse(jsonText);
        return parsedResponse;

    } catch (error) {
